const testItem = $('Split In Batches').first().json;
const chunks = $input.all().map(item => {
  // PGVector Store 'load' mode outputs: { document: { pageContent, metadata }, score }
  const doc = item.json.document || {};
  const text = (typeof doc === 'object' && doc.pageContent)
    ? String(doc.pageContent)
    : (typeof item.json.pageContent === 'string' ? item.json.pageContent : String(item.json.text || JSON.stringify(doc)));
  const score = item.json.score || 0;

  // Try to get chunk_id from metadata first
  let chunkId = 'unknown';
  const metadata = (typeof doc === 'object' && doc.metadata) ? doc.metadata : (item.json.metadata || {});
  if (metadata.chunk_id) {
    chunkId = metadata.chunk_id;
  } else {
    chunkId = identifyChunk(text);
  }

  return { text, score, chunkId };
});

function identifyChunk(text) {
  const t = String(text || '').toLowerCase();
  // Section 1: Registration
  if (t.includes('1.1') && t.includes('full-time status')) return 'chunk_1_1';
  if (t.includes('1.2') && t.includes('good academic standing')) return 'chunk_1_2';
  if (t.includes('1.3') && t.includes('academic warning')) return 'chunk_1_3';
  if (t.includes('1.4') && t.includes('academic probation')) return 'chunk_1_4';
  if (t.includes('1.5') && t.includes('system default limit')) return 'chunk_1_5';
  // Section 2: Prerequisites
  if (t.includes('2.1') && t.includes('prerequisite enforcement')) return 'chunk_2_1';
  if (t.includes('2.2') && t.includes('prerequisite conditions')) return 'chunk_2_2';
  if (t.includes('2.3') && t.includes('standard course offerings')) return 'chunk_2_3';
  if (t.includes('2.4') && t.includes('exception rule')) return 'chunk_2_4';
  if (t.includes('2.5') && t.includes('cross-program')) return 'chunk_2_5';
  // Section 3: Grading
  if (t.includes('3.1') && t.includes('grading scale')) return 'chunk_3_1';
  if (t.includes('3.2') && t.includes('non-passing')) return 'chunk_3_2';
  if (t.includes('3.3') && t.includes('attendance policy')) return 'chunk_3_3';
  if (t.includes('3.4') && t.includes('absence limit')) return 'chunk_3_4';
  // Section 4: Graduation
  if (t.includes('4.1') && t.includes('degree completion')) return 'chunk_4_1';
  if (t.includes('4.2') && t.includes('minimum gpa')) return 'chunk_4_2';
  if (t.includes('4.3') && t.includes('field training')) return 'chunk_4_3';
  // Section 5: Scheduling
  if (t.includes('5.1') && t.includes('schedule conflicts')) return 'chunk_5_1';
  if (t.includes('5.2') && t.includes('exemption')) return 'chunk_5_2';
  if (t.includes('5.3') && t.includes('university requirement')) return 'chunk_5_3';
  return 'unknown';
}

const idealGrades = testItem.ideal_grades || {};
const retrievedGrades = chunks.map(c => {
  return idealGrades[c.chunkId] || 0;
});

function computeDCG(rels) {
  return rels.reduce((sum, rel, i) => sum + (Math.pow(2, rel) - 1) / Math.log2(i + 2), 0);
}

const topK = chunks.length;
const allIdealGrades = Object.values(idealGrades).sort((a, b) => b - a).slice(0, topK);
const dcg = computeDCG(retrievedGrades);
const idcg = computeDCG(allIdealGrades);
const ndcg = idcg === 0 ? 0 : Math.round((dcg / idcg) * 10000) / 10000;
const hitRate = retrievedGrades.some(g => g >= 2) ? 1 : 0;

return [{json: {
  ...testItem,
  retrieved_chunks: chunks.map((c, i) => ({text: c.text.substring(0, 200), chunk_id: c.chunkId, relevance_grade: retrievedGrades[i], score: c.score})),
  ndcg_at_3: ndcg,
  dcg: Math.round(dcg * 10000) / 10000,
  idcg: Math.round(idcg * 10000) / 10000,
  hit_rate: hitRate,
  retrieved_grades: retrievedGrades,
  chunks_retrieved: chunks.length
}}];

