const metricsItem = $('Compute NDCG@3').first().json;
const llmScore = $input.first().json.context_relevance || 0;
return [{json: {...metricsItem, context_relevance: llmScore}}];

const items = $input.all();
const results = items.map(i => i.json);
const n = results.length;

const avgNDCG = results.reduce((s, r) => s + (r.ndcg_at_3 || 0), 0) / n;
const avgHitRate = results.reduce((s, r) => s + (r.hit_rate || 0), 0) / n;
const avgRelevance = results.reduce((s, r) => s + (r.context_relevance || 0), 0) / n;

const ndcgValues = results.map(r => r.ndcg_at_3 || 0).sort((a, b) => a - b);
const medianNDCG = n % 2 === 0 ? (ndcgValues[n/2-1] + ndcgValues[n/2]) / 2 : ndcgValues[Math.floor(n/2)];
const minNDCG = ndcgValues[0];
const maxNDCG = ndcgValues[n - 1];

const sections = {};
results.forEach(r => {
  const sec = r.section || 'Unknown';
  if (!sections[sec]) sections[sec] = {count: 0, ndcg_sum: 0, hit_sum: 0, rel_sum: 0};
  sections[sec].count++;
  sections[sec].ndcg_sum += r.ndcg_at_3 || 0;
  sections[sec].hit_sum += r.hit_rate || 0;
  sections[sec].rel_sum += r.context_relevance || 0;
});
const sectionBreakdown = {};
for (const [sec, data] of Object.entries(sections)) {
  sectionBreakdown[sec] = {
    count: data.count,
    avg_ndcg: Math.round((data.ndcg_sum / data.count) * 10000) / 10000,
    avg_hit_rate: Math.round((data.hit_sum / data.count) * 10000) / 10000,
    avg_context_relevance: Math.round((data.rel_sum / data.count) * 10000) / 10000
  };
}

let csv = 'test_id,section,difficulty,question,ground_truth,ndcg_at_3,hit_rate,context_relevance\n';
results.forEach(r => {
  csv += `${r.test_id},"${(r.section||'').replace(/"/g,'""')}","${r.difficulty||''}","${(r.question||'').replace(/"/g,'""')}","${(r.ground_truth||'').replace(/"/g,'""')}",${r.ndcg_at_3},${r.hit_rate},${r.context_relevance}\n`;
});

return [{json: {
  total_tests: n,
  overall_ndcg_at_3: Math.round(avgNDCG * 10000) / 10000,
  overall_hit_rate: Math.round(avgHitRate * 10000) / 10000,
  overall_context_relevance: Math.round(avgRelevance * 10000) / 10000,
  ndcg_stats: {mean: Math.round(avgNDCG*10000)/10000, median: Math.round(medianNDCG*10000)/10000, min: Math.round(minNDCG*10000)/10000, max: Math.round(maxNDCG*10000)/10000},
  section_breakdown: sectionBreakdown,
  csv_output: csv,
  individual_results: results,
  summary: `RAG Evaluation (NDCG@3): ${n} tests | NDCG@3: ${(avgNDCG*100).toFixed(1)}% | Hit Rate: ${(avgHitRate*100).toFixed(1)}% | Context Relevance: ${(avgRelevance*100).toFixed(1)}%`
}}];
